//-------------------------------------------------------------------------
// function name : f_SaveAndAutoEDI
// function desc : 저장(A/S)
//------------------------------------------------------------------------- 
scwin.f_SaveAndAutoEDI = async function(flag){
    if (lc_qryClsCd.getValue() == "Y") {
        await $c.win.alert("배차후에는 이용할 수 없습니다.");
        return false;
    }

    for (var i = 0; i < ds_results.getTotalRow(); i++) {
        if (ds_results.getCellData(i, "vehclClntNo") == ds_results.getCellData(i, "bilgClntNo")) {
            await $c.win.alert("오더의 청구거래처와 협력 운송업체가 동일한 경우 저장 할 수 없습니다.");
            return false;
        }
    } 

    var arrParam = new Array();
    var arryCnt = 0;

    debugger;
    for (var i = 0; i < ds_results.getTotalRow(); i++){
        if (ds_results.getRowStatus(i) == "U") {        //ds_results.RowStatus(i) == 3
            arrParam[arryCnt] = i;
            arryCnt++;
        }
    }

    await scwin.f_Save("NO");

    for (var i = 0; i < arrParam.length; i++){

        if (ds_results.getCellData(arrParam[i], "vehclNo") == ""){
            await $c.win.alert("컨테이너 "+ds_results.getCellData(arrParam[i], "cntrNo")+" 는 차량번호가 없어서 전송할 수 없습니다." );
            continue;

        } else {
            if (ds_results.getCellData(arrParam[i], "crryinEdiFlag") == "N" && ds_results.getCellData(arrParam[i], "crryoutEdiFlag") == "N" ) {
                await $c.gus.cfAlertMsg("컨테이너 " + ds_results.getCellData(arrParam[i], "cntrNo")
                            +", " + ds_results.getCellData(arrParam[i], "dptWrkPlNm")
                            +", " + ds_results.getCellData(arrParam[i], "arvWrkPlNm")
                            +" 는 EDI등록 대상이 아닙니다");
                continue;
            }
            if ( (ds_results.getCellData(arrParam[i], "crryoutEdiType") != "CO" && ds_results.getCellData(arrParam[i], "crryoutEdiType") != "CD")
                && (ds_results.getCellData(arrParam[i], "crryinEdiType") != "CO" && ds_results.getCellData(arrParam[i], "crryinEdiType") != "CD")
                ) {
                await $c.gus.cfAlertMsg("컨테이너 "+ds_results.getCellData(arrParam[i], "cntrNo")
                            +", "+ds_results.getCellData(arrParam[i], "dptWrkPlNm")
                            +", "+ds_results.getCellData(arrParam[i], "arvWrkPlNm")
                            +" 는 EDI등록 대상이 아닙니다");
                continue;
            }

            if (flag == "AUTO") {
                await scwin.f_crryInOutEDI(false, true, true, arrParam[i], true);
            } else if (flag == "MANUAL") {
                await scwin.f_crryInOutEDI(false, false, false, arrParam[i], true);
            }


        }//else
    }

    scwin.f_Retrieve();
};



