// 반출EDI 컬럼
scwin.customFormatterOut = function(data, formattedData, rowIndex, colIndex) {
    var map = {
        "": "미등록",
        "3": "미전송",
        "1": "전송완료",
        "0": "전송대기",
        "5": "필수항목오류",
    };

    var typeMap = {
        "CO": "(COPINO)",
        "CD": "(COPI_CODECO)"
    };

    var crryOut = (map[ds_results.getCellData(rowIndex, "crryoutEdiFlag")] || "") + (typeMap[ds_results.getCellData(rowIndex, "crryoutEdiType")] || "");
    return crryOut;
};

